@pytest.mark.asyncio
async def test_anthropic_tool_calling() -> None:
    """Chat request to Anthropic provider with a tool definition; assistant responds with a tool call."""
    request = {
        "max_tokens": 256,
        "messages": [{"content": "What is the weather in London?", "role": "user"}],
        "model": "anthropic/claude-3-5-sonnet-20241022",
        "tool_choice": "auto",
        "tools": [
            {
                "function": {
                    "description": "Get the current weather for a given location",
                    "name": "get_weather",
                    "parameters": {
                        "properties": {
                            "location": {
                                "description": "The city and country, e.g. London, UK",
                                "type": "string",
                            },
                            "unit": {
                                "description": "The temperature unit to use",
                                "enum": ["celsius", "fahrenheit"],
                                "type": "string",
                            },
                        },
                        "required": ["location"],
                        "type": "object",
                    },
                },
                "type": "function",
            }
        ],
    }
    client = create_client(
        api_key="test-key",
        base_url=os.environ["MOCK_SERVER_URL"] + "/fixtures/anthropic_tool_calling",
    )
    result = await client.chat(request)
    assert len(result.choices) == 1  # noqa: S101
    assert result.choices[0].message.tool_calls  # noqa: S101
    assert (
        result.choices[0].message.tool_calls[0].function.name.strip() == "get_weather"
    )  # noqa: S101
    assert result.choices[0].finish_reason.strip() == "tool_calls"  # noqa: S101


